from pathlib import Path
import csv, re, shutil
import fitz, pytesseract
from PIL import Image

DOCS = Path('/app/documents')
INV = Path('/app/invoices')
OTH = Path('/app/other')
INV.mkdir(exist_ok=True)
OTH.mkdir(exist_ok=True)

invoice_keywords = [
    'invoice', 'invoice no', 'invoice number', 'bill to', 'amount due',
    'grand total', 'totalprice', 'date due', 'vat [%]'
]
other_keywords = ['purchase order', 'purchase orders', 'stock report', 'inter-office correspondence']

num_pattern = re.compile(r'[-+]?\d[\d\s.,]*\d|[-+]?\d')

def extract_text(path: Path) -> str:
    if path.suffix.lower() == '.pdf':
        doc = fitz.open(path)
        text = '\n'.join(page.get_text() for page in doc)
        doc.close()
        return text
    img = Image.open(path)
    return pytesseract.image_to_string(img, config='--psm 6')


def normalize_number(token: str):
    s = token.strip()
    s = re.sub(r'[^\d,.-]', '', s.replace(' ', ''))
    if not s or not re.search(r'\d', s):
        return None
    if ',' in s and '.' in s:
        if s.rfind(',') > s.rfind('.'):
            s = s.replace('.', '')
            s = s.replace(',', '.')
        else:
            s = s.replace(',', '')
    elif ',' in s:
        parts = s.split(',')
        if len(parts) > 1 and len(parts[-1]) in (1, 2):
            s = ''.join(parts[:-1]) + '.' + parts[-1]
        else:
            s = ''.join(parts)
    elif '.' in s:
        parts = s.split('.')
        if len(parts) > 2:
            if len(parts[-1]) in (1, 2):
                s = ''.join(parts[:-1]) + '.' + parts[-1]
            else:
                s = ''.join(parts)
    try:
        return float(s)
    except ValueError:
        return None


def extract_numbers(text: str):
    vals = []
    for m in num_pattern.findall(text):
        v = normalize_number(m)
        if v is not None:
            vals.append(v)
    return vals


def classify(text: str) -> str:
    low = text.lower()
    if any(k in low for k in other_keywords):
        return 'other'
    score = sum(1 for k in invoice_keywords if k in low)
    if score >= 1 and 'invoice' in low:
        return 'invoice'
    if any(k in low for k in ['amount due', 'bill to', 'grand total', 'totalprice']):
        return 'invoice'
    return 'other'


def parse_invoice_amounts(text: str):
    lines = [line.strip() for line in text.splitlines() if line.strip()]
    lower_lines = [line.lower() for line in lines]

    # Table-style total row: net, vat, gross
    for i, low in enumerate(lower_lines):
        if 'total' in low:
            nums = extract_numbers(lines[i])
            if len(nums) >= 3:
                return nums[-1], nums[-2]

    total_candidates = []
    amount_due_candidates = []
    grand_total_candidates = []
    totalprice_candidates = []
    vat_candidates = []

    label_patterns = [
        ('grand_total', re.compile(r'grand\s*total', re.I)),
        ('amount_due', re.compile(r'amount\s*due', re.I)),
        ('totalprice', re.compile(r'total\s*price|totalprice', re.I)),
        ('total', re.compile(r'\btotal\b', re.I)),
        ('vat', re.compile(r'\bvat\b|\bgst\b|\btax\b', re.I)),
    ]

    for i, line in enumerate(lines):
        low = lower_lines[i]
        for label, pattern in label_patterns:
            if not pattern.search(line):
                continue
            if label == 'vat' and re.search(r'tax\s*id', low):
                continue
            nums = extract_numbers(line)
            if not nums and i + 1 < len(lines):
                nums = extract_numbers(lines[i + 1])
            if not nums:
                continue
            value = nums[-1]
            if label == 'grand_total':
                grand_total_candidates.append(value)
            elif label == 'amount_due':
                amount_due_candidates.append(value)
            elif label == 'totalprice':
                totalprice_candidates.append(value)
            elif label == 'total':
                if 'subtotal' not in low:
                    total_candidates.append(value)
            elif label == 'vat':
                vat_candidates.append(value)

    total_amount = None
    if total_candidates:
        total_amount = total_candidates[-1]
    elif grand_total_candidates:
        total_amount = grand_total_candidates[-1]
    elif totalprice_candidates:
        total_amount = totalprice_candidates[-1]
    elif amount_due_candidates:
        total_amount = amount_due_candidates[-1]

    # Special rule: if both Total and Amount Due exist and differ, use Total
    if total_candidates and amount_due_candidates:
        if abs(total_candidates[-1] - amount_due_candidates[-1]) > 1e-9:
            total_amount = total_candidates[-1]

    vat_amount = vat_candidates[-1] if vat_candidates else 0.0
    if total_amount is None:
        total_amount = 0.0
    return total_amount, vat_amount

files = sorted([p for p in DOCS.iterdir() if p.is_file()], key=lambda p: p.name)
invoice_rows = []
for path in files:
    text = extract_text(path)
    kind = classify(text)
    dest_dir = INV if kind == 'invoice' else OTH
    shutil.move(str(path), str(dest_dir / path.name))
    if kind == 'invoice':
        total_amount, vat_amount = parse_invoice_amounts(text)
        invoice_rows.append((path.name, total_amount, vat_amount))

invoice_rows.sort(key=lambda x: x[0])
total_total = sum(row[1] for row in invoice_rows)
total_vat = sum(row[2] for row in invoice_rows)

with open(INV / 'summary.csv', 'w', newline='') as f:
    writer = csv.writer(f)
    writer.writerow(['filename', 'total_amount', 'vat_amount'])
    for filename, total_amount, vat_amount in invoice_rows:
        writer.writerow([filename, f'{total_amount:.2f}', f'{vat_amount:.2f}'])
    writer.writerow(['total', f'{total_total:.2f}', f'{total_vat:.2f}'])

print('processed', len(files), 'files')
print('invoices', len(invoice_rows))
